const bankBalance = parseFloat($('Get Trust Bank Balance').item.json.balance ?? 0);
const clientLedgers = $('Get Client Trust Ledgers').item.json.clientLedgers ?? [];
const creditors = $('Get Trust Creditors').item.json.creditors ?? [];

const clientLedgersSum = clientLedgers.reduce((sum, l) => sum + parseFloat(l.balance ?? 0), 0);
const creditorsSum = creditors.reduce((sum, c) => sum + parseFloat(c.amount ?? 0), 0);
const variance = Math.abs(bankBalance - clientLedgersSum - creditorsSum);
const isReconciled = variance <= 1.00;

const negativeBalances = clientLedgers
  .filter(l => parseFloat(l.balance ?? 0) < 0)
  .map(l => ({ clientName: l.clientName ?? l.name ?? 'Unknown', balance: parseFloat(l.balance ?? 0) }));

const recentTx = $('Get Trust Bank Balance').item.json.recentTransactions ?? [];
const unusualTransactions = recentTx.filter(t => {
  const amount = Math.abs(parseFloat(t.amount ?? 0));
  const day = new Date(t.date ?? t.transactionDate ?? Date.now()).getDay();
  return amount >= 10000 || day === 0 || day === 6;
});

return [{
  json: {
    bankBalance: Math.round(bankBalance * 100) / 100,
    clientLedgersSum: Math.round(clientLedgersSum * 100) / 100,
    creditorsSum: Math.round(creditorsSum * 100) / 100,
    variance: Math.round(variance * 100) / 100,
    isReconciled,
    negativeBalances,
    negativeBalancesCount: negativeBalances.length,
    unusualTransactionsCount: unusualTransactions.length,
    checkDate: new Date().toISOString().split('T')[0]
  }
}];

const data = $('Three-Way Reconciliation').item.json;
const now = new Date();
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1)
  .toLocaleDateString('en-AU', { month: 'long', year: 'numeric' });

const statusColour = data.isReconciled ? '#27ae60' : '#e74c3c';
const statusText = data.isReconciled ? '✓ RECONCILED' : '⚠ VARIANCE DETECTED';

const reportHtml = `
<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">
<h1 style="color:#2c3e50;">Trust Account Reconciliation Report</h1>
<h2 style="color:#7f8c8d;">${prevMonth}</h2>
<p>Generated: ${now.toLocaleDateString('en-AU')}</p>
<table border="1" cellpadding="10" cellspacing="0" style="border-collapse:collapse;width:100%;">
  <tr style="background:#ecf0f1;"><th>Metric</th><th>Value</th></tr>
  <tr><td>Trust Bank Balance</td><td>$${data.bankBalance?.toLocaleString('en-AU', {minimumFractionDigits:2})}</td></tr>
  <tr><td>Sum of Client Ledgers</td><td>$${data.clientLedgersSum?.toLocaleString('en-AU', {minimumFractionDigits:2})}</td></tr>
  <tr><td>Sum of Trust Creditors</td><td>$${data.creditorsSum?.toLocaleString('en-AU', {minimumFractionDigits:2})}</td></tr>
  <tr><td><strong>Variance</strong></td><td><strong>$${data.variance?.toFixed(2)}</strong></td></tr>
  <tr><td>Status</td><td style="color:${statusColour};"><strong>${statusText}</strong></td></tr>
  <tr><td>Negative Ledger Balances Detected</td><td>${data.negativeBalancesCount}</td></tr>
  <tr><td>Unusual Transactions Flagged</td><td>${data.unusualTransactionsCount}</td></tr>
</table>
<p style="color:#7f8c8d;font-size:12px;"><em>Auto-generated by APEX Trust Monitor. This report does not replace a formal trust audit as required by your state Law Society.</em></p>
</body></html>`;

return [{ json: { ...data, reportHtml, reportMonth: prevMonth } }];
